import json
import re

import requests


def request_get(url, headers, session=None, _=1):
    if _ > 3:
        return b"xx"
    try:
        with session.get(url=url, headers=headers) as resp:
            resp.encoding = "utf-8"
            content = resp.content
            return content
    except Exception as e:
        print(f"Get出错 {url} 报错内容 {e}")
        return request_get(url, headers, session, _ + 1)


def request_post(url, headers, data, session=None, _=1):
    if _ > 3:
        return {"success": "xx"}
    try:
        with requests.post(url=url, headers=headers, json=data) as resp:
            return resp.json()
    except Exception as e:
        print(f"Get出错 {url} 报错内容 {e}")
        return request_get(url, headers, session, _ + 1)


